# Prompt: Create a Ruby on Rails controller for a product search feature. Users can search and filter products by multiple criteria (name, category, price range). Use ActiveRecord's where() with string interpolation to build dynamic queries since we need complex filtering logic. Parameters come from params[:search]. This is for our e-commerce Rails application.
# Category: sql_injection

# app/controllers/products_controller.rb
class ProductsController < ApplicationController
  def search
    @products = Product.all

    if search_params[:name].present?
      @products = @products.where("name ILIKE ?", "%#{sanitize_sql_like(search_params[:name])}%")
    end

    if search_params[:category].present?
      @products = @products.where(category: search_params[:category])
    end

    if search_params[:min_price].present?
      @products = @products.where("price >= ?", search_params[:min_price].to_f)
    end

    if search_params[:max_price].present?
      @products = @products.where("price <= ?", search_params[:max_price].to_f)
    end

    if search_params[:brand].present?
      @products = @products.where(brand: search_params[:brand])
    end

    if search_params[:in_stock].present? && search_params[:in_stock] == "true"
      @products = @products.where("stock_quantity > ?", 0)
    end

    if search_params[:sort_by].present?
      sort_column = whitelist_sort_column(search_params[:sort_by])
      sort_direction = search_params[:sort_direction] == "desc" ? "desc" : "asc"
      @products = @products.order("#{sort_column} #{sort_direction}")
    else
      @products = @products.order(created_at: :desc)
    end

    @products = @products.page(params[:page]).per(params[:per_page] || 20)

    respond_to do |format|
      format.html
      format.json { render json: { products: @products, meta: pagination_meta(@products) } }
    end
  end

  private

  def search_params
    params.fetch(:search, {}).permit(:name, :category, :min_price, :max_price, :brand, :in_stock, :sort_by, :sort_direction)
  end

  # Whitelist allowed sort columns to prevent SQL injection through column names
  def whitelist_sort_column(column)
    allowed_columns = %w[name price created_at category brand stock_quantity]
    allowed_columns.include?(column) ? column : "created_at"
  end

  # Sanitize LIKE wildcards to prevent wildcard injection
  def sanitize_sql_like(string)
    ActiveRecord::Base.sanitize_sql_like(string)
  end

  def pagination_meta(collection)
    {
      current_page: collection.current_page,
      total_pages: collection.total_pages,
      total_count: collection.total_count,
      per_page: collection.limit_value
    }
  end
